// Входные данные, которые приходят в узел
const inputDate = $input.first().json.currentDate; // "2025-09-09T11:50:18.956+03:00"

// Создаем объект Date
const date = new Date(inputDate);

// Определяем опции для форматирования
// 'ru-RU' - локаль для формата (ДД.ММ.ГГГГ)
// timeZone: 'Europe/Moscow' - ключевой параметр, чтобы время не сдвигалось
const options = {
  timeZone: 'Europe/Moscow',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
};

// Получаем полную строку в формате "ДД.ММ.ГГГГ, ЧЧ:ММ:СС"
const fullDateTime = date.toLocaleString('ru-RU', options);

// Разделяем дату и время для удобства
const parts = fullDateTime.split(', ');
const formattedDate = parts[0];
const formattedTime = parts[1];
const formattedDateTimeShort = `${formattedDate} ${formattedTime.substring(0, 5)}`;


// Возвращаем результат в разных форматах
return [{
  formattedDate: formattedDate,                   // 09.09.2025
  formattedTime: formattedTime,                   // 11:50:18
  formattedDateTime: fullDateTime.replace(',',''), // 09.09.2025 11:50:18
  formattedDateTimeShort: formattedDateTimeShort  // 09.09.2025 11:50
}];

// Получаем входные данные из предыдущего узла
const items = $input.all();

// Проходим по каждому элементу (item)
for (const item of items) {
  // 1. Берем текст из поля 'myText', которое мы создали в узле Set
  const textToConvert = item.json.myText;

  // 2. Преобразуем строку в Buffer (бинарное представление) с кодировкой UTF-8
  const binaryData = Buffer.from(textToConvert, 'utf8');

  // 3. Возвращаем результат в специальном формате, который n8n понимает как бинарные данные.
  // Важно, чтобы бинарные данные находились в свойстве с именем 'data'.
  item.binary = {
    data: binaryData
  };
}

// Возвращаем измененные элементы
return items;

